1	use crate::multiplexer::UdtMultiplexer;
2	use crate::packet::UdtPacket;
3	use crate::socket::{SocketId, UdtSocket};
4	use crate::udt::{SocketRef, Udt, UDT_DEBUG};
5	use nix::sys::socket::{SockaddrIn, SockaddrIn6};
6	use std::collections::{BTreeMap, VecDeque};
7	use std::net::SocketAddr;
8	use std::sync::{Arc, Mutex, Weak};
9	use tokio::io::{Error, ErrorKind, Result};
10	use tokio::net::UdpSocket;
11	use tokio::time::{Duration, Instant};
12	
13	#[cfg(not(target_os = "linux"))]
14	use tokio::time::sleep;
15	#[cfg(target_os = "linux")]
16	use tokio_timerfd::sleep;
17	
18	const TIMERS_CHECK_INTERVAL: Duration = Duration::from_millis(100);
19	const UDP_RCV_TIMEOUT: Duration = Duration::from_micros(30);
20	
21	#[derive(Debug)]
22	pub(crate) struct UdtRcvQueue {
23	    sockets: Mutex<VecDeque<(Instant, SocketId)>>,
24	    mss: u32,
25	    channel: Arc<UdpSocket>,
26	    multiplexer: Mutex<Weak<UdtMultiplexer>>,
27	    socket_refs: Mutex<BTreeMap<SocketId, Weak<UdtSocket>>>,
28	}
29	
30	impl UdtRcvQueue {
31	    pub fn new(channel: Arc<UdpSocket>, mss: u32) -> Self {
32	        Self {
33	            sockets: Mutex::new(VecDeque::new()),
34	            mss,
35	            channel,
36	            multiplexer: Mutex::new(Weak::new()),
37	            socket_refs: Mutex::new(BTreeMap::new()),
38	        }
39	    }
40	
41	    pub fn push_back(&self, socket_id: SocketId) {
42	        self.sockets
43	            .lock()
44	            .unwrap()
45	            .push_back((Instant::now(), socket_id));
46	    }
47	
48	    fn update(&self, socket_id: SocketId) {
49	        let mut queue = self.sockets.lock().unwrap();
50	        queue.retain(|(_, id)| socket_id != *id);
51	        queue.push_back((Instant::now(), socket_id));
52	    }
53	
54	    pub fn set_multiplexer(&self, mux: &Arc<UdtMultiplexer>) {
55	        *self.multiplexer.lock().unwrap() = Arc::downgrade(mux);
56	    }
57	
58	    async fn get_socket(&self, socket_id: SocketId) -> Option<SocketRef> {
59	        let known_socket = self.socket_refs.lock().unwrap().get(&socket_id).cloned();
60	        if let Some(socket) = known_socket {
61	            socket.upgrade()
62	        } else if let Some(socket) = Udt::get().read().await.get_socket(socket_id) {
63	            self.socket_refs
64	                .lock()
65	                .unwrap()
66	                .insert(socket_id, Arc::downgrade(&socket));
67	            Some(socket)
68	        } else {
69	            None
70	        }
71	    }
72	
73	    #[cfg(target_os = "linux")]
74	    fn receive_packets(&self, buf: &mut [u8]) -> Result<Vec<(usize, SocketAddr)>> {
75	        use nix::sys::socket::{
76	            recvmmsg, AddressFamily, MsgFlags, RecvMmsgData, SockaddrLike, SockaddrStorage,
77	        };
78	        use std::io::IoSliceMut;
79	        use std::os::unix::io::AsRawFd;
80	        use tokio::io::Interest;
81	        let bufs = buf.chunks_exact_mut(self.mss as usize);
82	        let mut recv_mesg_data: Vec<RecvMmsgData<_>> = bufs
83	            .map(|b| RecvMmsgData {
84	                iov: [IoSliceMut::new(&mut b[..])],
85	                cmsg_buffer: None,
86	            })
87	            .collect();
88	
89	        self.channel.try_io(Interest::READABLE, || {
90	            let msgs = recvmmsg(
91	                self.channel.as_raw_fd(),
92	                &mut recv_mesg_data,
93	                MsgFlags::MSG_DONTWAIT,
94	                None,
95	            )
96	            .map_err(|err| {
97	                if err == nix::errno::Errno::EWOULDBLOCK {
98	                    return Error::new(ErrorKind::WouldBlock, "recvmmsg would block");
99	                }
100	                Error::new(ErrorKind::Other, err)
101	            })?
102	            .iter()
103	            .map(|msg| {
104	                let addr: SockaddrStorage = msg.address.unwrap();
105	                let socket_addr: SocketAddr = match addr.family() {
106	                    Some(AddressFamily::Inet) => {
107	                        Self::addr_v4_from_sockaddrin(*addr.as_sockaddr_in().unwrap()).into()
108	                    }
109	                    Some(AddressFamily::Inet6) => {
110	                        Self::addr_v6_from_sockaddrin6(*addr.as_sockaddr_in6().unwrap()).into()
111	                    }
112	                    _ => unreachable!(),
113	                };
114	                (msg.bytes, socket_addr)
115	            })
116	            .collect();
117	            Ok(msgs)
118	        })
119	    }
120	
121	    #[cfg(not(target_os = "linux"))]
122	    fn receive_packets(&self, buf: &mut [u8]) -> Result<Vec<(usize, SocketAddr)>> {
123	        let bufs = buf.chunks_exact_mut(self.mss as usize);
124	        let mut msgs = vec![];
125	        for mut buf in bufs {
126	            match self.channel.try_recv_from(&mut buf) {
127	                Ok(msg) => {
128	                    msgs.push(msg);
129	                }
130	                Err(e) if e.kind() == ErrorKind::WouldBlock => break,
131	                Err(e) => return Err(e),
132	            }
133	        }
134	        Ok(msgs)
135	    }
136	
137	    pub(crate) async fn worker(&self) -> Result<()> {
138	        let mut buf = vec![0_u8; self.mss as usize * 100];
139	        loop {
140	            let packets = {
141	                let msgs = self.receive_packets(&mut buf).unwrap_or_default();
142	                if !msgs.is_empty() {
143	                    let packets: Vec<_> = msgs
144	                        .into_iter()
145	                        .zip(buf.chunks_exact_mut(self.mss as usize))
146	                        .filter_map(|((nbytes, addr), buf)| {
147	                            let packet = UdtPacket::deserialize(&buf[..nbytes]).ok()?;
148	
149	                            Some((packet, addr))
150	                        })
151	                        .collect();
152	                    Some(packets)
153	                } else {
154	                    tokio::select! {
155	                        _ = sleep(UDP_RCV_TIMEOUT) => (),
156	                        _ = self.channel.readable() => ()
157	                    };
158	                    None
159	                }
160	            };
161	
162	            for (packet, addr) in packets.into_iter().flatten() {
163	                let socket_id = packet.get_dest_socket_id();
164	                if socket_id == 0 {
165	                    if let Some(handshake) = packet.handshake() {
166	                        let mux = {
167	                            let lock = self.multiplexer.lock().unwrap();
168	                            lock.upgrade()
169	                        };
170	                        if let Some(mux) = mux {
171	                            let listener = mux.listener.read().await;
172	                            if let Some(listener) = &*listener {
173	                                listener.listen_on_handshake(addr, handshake).await?;
174	                            }
175	                        }
176	                    } else {
177	                        return Err(Error::new(
178	                            ErrorKind::InvalidData,
179	                            "received non-hanshake packet with socket 0",
180	                        ));
181	                    }
182	                } else if let Some(socket) = self.get_socket(socket_id).await {
183	                    if socket.peer_addr() == Some(addr) && socket.status().is_alive() {
184	                        socket.process_packet(packet).await?;
185	                        socket.check_timers().await;
186	                        self.update(socket_id);
187	                    } else if *UDT_DEBUG {
188	                        eprintln!("Ignoring packet {:?}", packet);
189	                    }
190	                } else {
191	                    // TODO: implement rendezvous queue for rendezvous mode
192	
193	                    if *UDT_DEBUG {
194	                        eprintln!("socket not found for socket_id {}", socket_id);
195	                        dbg!(packet);
196	                    }
197	                }
198	            }
199	
200	            let to_check = {
201	                let mut to_check = vec![];
202	                let mut sockets = self.sockets.lock().unwrap();
203	                while sockets
204	                    .front()
205	                    .map(|(ts, _)| ts.elapsed() > TIMERS_CHECK_INTERVAL)
206	                    .unwrap_or(false)
207	                {
208	                    to_check.push(sockets.pop_front().unwrap().1);
209	                }
210	                to_check
211	            };
212	
213	            for socket_id in to_check {
214	                if let Some(socket) = self.get_socket(socket_id).await {
215	                    if socket.status().is_alive() {
216	                        socket.check_timers().await;
217	                        self.update(socket_id);
218	                    }
219	                }
220	            }
221	        }
222	    }
223	
224	    // TEMP: waiting for "nix" next release (> 0.24.2) to include these conversions
225	    fn addr_v4_from_sockaddrin(addr: SockaddrIn) -> std::net::SocketAddrV4 {
226	        std::net::SocketAddrV4::new(std::net::Ipv4Addr::from(addr.ip()), addr.port())
227	    }
228	
229	    fn addr_v6_from_sockaddrin6(addr: SockaddrIn6) -> std::net::SocketAddrV6 {
230	        std::net::SocketAddrV6::new(
231	            addr.ip(),
232	            addr.port(),
233	            u32::from_be(addr.flowinfo()),
234	            u32::from_be(addr.scope_id()),
235	        )
236	    }
237	}
